class Solution {
    public double meanAbsoluteDeviation(List<Double> numbers) {
        double sum = 0;
        double mean;

        for (Double num : numbers) {
            sum += num;
        }

        mean = sum / numbers.size();

        double deviationSum = 0;
        for (Double num : numbers) {
            deviationSum += Math.abs(num - mean);
        }

        return deviationSum / numbers.size();
    }
